SELECT t.tmid, t.year, t.name, t.w, t.gf, COUNT(DISTINCT c.coachid) AS all_star_coaches FROM teams AS t JOIN teamvsteam AS tvt ON t.tmid = tvt.tmid AND t.year = tvt.year JOIN coaches AS c ON t.tmid = c.tmid JOIN awardscoaches AS a ON c.coachid = a.coachid JOIN abbrev AS ab ON t.confid = ab.code WHERE (ab.code = 'EC' OR ab.code = 'WA') GROUP BY t.tmid, t.year, t.name, t.w, t.gf HAVING (COUNT(DISTINCT c.coachid) >= 1)
